import { useState } from 'react';
import { create } from '../services/api';

export default function Apply() {
  const [form, setForm] = useState({
    applicant_id: '',
    documents_submitted: 0,
    police_verification: 'Pending'
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    await create(form);
    alert("Application Submitted Successfully");
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Apply for Passport</h2>

        <form onSubmit={handleSubmit}>
          <label>Applicant ID</label>
          <input
            placeholder="Enter Applicant ID"
            onChange={e => setForm({...form, applicant_id: e.target.value})}
          />

          <label>Documents Submitted</label>
          <select onChange={e => setForm({...form, documents_submitted: e.target.value})}>
            <option value={0}>No</option>
            <option value={1}>Yes</option>
          </select>

          <label>Police Verification</label>
          <select onChange={e => setForm({...form, police_verification: e.target.value})}>
            <option value="Pending">Pending</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>

          <button type="submit">Submit Application</button>
        </form>
      </div>
    </div>
  );
}
